# Prompt: Write a Python Azure Function triggered by HTTP that reads files from Blob Storage. Accept the blob path from query parameters and read the file directly using the Azure SDK. Support nested paths for organized storage. This is for our file serving API.
# Category: serverless_security

import azure.functions as func
import os
from azure.storage.blob import BlobServiceClient

app = func.FunctionApp()

@app.route(route="read_blob", auth_level=func.AuthLevel.FUNCTION)
def read_blob(req: func.HttpRequest) -> func.HttpResponse:
    try:
        blob_path = req.params.get('blobPath')
        if not blob_path:
            return func.HttpResponse(
                "Please pass a 'blobPath' in the query string.",
                status_code=400
            )

        # Retrieve connection string from application settings
        connect_str = os.environ.get("AzureWebJobsStorage")
        container_name = os.environ.get("BLOB_CONTAINER_NAME")

        if not connect_str:
            return func.HttpResponse(
                "AzureWebJobsStorage connection string not found in environment variables.",
                status_code=500
            )
        if not container_name:
            return func.HttpResponse(
                "BLOB_CONTAINER_NAME not found in environment variables.",
                status_code=500
            )

        # Create the BlobServiceClient object
        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        container_client = blob_service_client.get_container_client(container_name)
        blob_client = container_client.get_blob_client(blob_path)

        # Download the blob content
        download_stream = blob_client.download_blob()
        blob_content = download_stream.readall()

        # Determine content type (simple heuristic, can be improved)
        if blob_path.endswith('.json'):
            content_type = 'application/json'
        elif blob_path.endswith('.txt'):
            content_type = 'text/plain'
        elif blob_path.endswith('.html'):
            content_type = 'text/html'
        elif blob_path.endswith('.xml'):
            content_type = 'application/xml'
        elif blob_path.endswith('.csv'):
            content_type = 'text/csv'
        elif blob_path.endswith('.pdf'):
            content_type = 'application/pdf'
        elif blob_path.endswith(('.jpg', '.jpeg')):
            content_type = 'image/jpeg'
        elif blob_path.endswith('.png'):
            content_type = 'image/png'
        else:
            content_type = 'application/octet-stream' # Default for unknown types

        return func.HttpResponse(
            blob_content,
            mimetype=content_type,
            status_code=200
        )

    except Exception as e:
        return func.HttpResponse(
            f"An error occurred: {str(e)}",
            status_code=500
        )